const input = $input.first().json;
const body = input.body || input;

const product_name = body.product_name;
const image_url = body.image_url;
const marketplace = body.marketplace || 'WB';

if (!product_name) throw new Error('product_name is required');
if (!image_url) throw new Error('image_url is required');

// Concept templates for infographic generation
const validConcepts = ['studio', 'lifestyle', 'flatlay', 'minimal', 'model'];
const concept = validConcepts.includes(body.concept) ? body.concept : 'studio';

return [{ json: {
  product_name,
  image_url,
  marketplace,
  concept,
  artikuls: body.artikuls || [],
  product_description: body.product_description || '',
  target_audience: body.target_audience || '',
  key_features: body.key_features || '',
  style: body.style || 'modern',
  color_scheme: body.color_scheme || 'auto',
  include_price: body.include_price || false,
  price: body.price || '',
  include_badge: body.include_badge || false,
  badge_text: body.badge_text || '',
  extra_instructions: body.extra_instructions || '',
  session_id: body.session_id || null,
  callback_url: body.callback_url || ''
}}];

const settings = {};
for (const row of $input.all()) {
  settings[row.json.key] = row.json.value;
}
const params = $('🔍 Валидация').first().json;

const systemPrompt = settings.ai_system_prompt || 'Ты — профессиональный дизайнер карточек товаров для маркетплейсов.';
const model = settings.ai_model || 'gpt-4o';
const baseUrl = (settings.ai_base_url || 'https://gptunnel.ru/v1').replace(/\/+$/, '');

return [{ json: { ...params, systemPrompt, model, baseUrl } }];

const ctx = $input.first().json;

const conceptNames = { studio: 'Studio (белый фон, студийный свет)', lifestyle: 'Lifestyle (в контексте использования)', flatlay: 'Flatlay (вид сверху)', minimal: 'Минимализм', model: 'На модели' };

const userPrompt = `Проанализируй изображение товара и создай подробный JSON с данными для карточки товара.

Товар: ${ctx.product_name}
Маркетплейс: ${ctx.marketplace}
Выбранная концепция: ${ctx.concept} — ${conceptNames[ctx.concept] || ctx.concept}
Описание от продавца: ${ctx.product_description || 'нет'}
Целевая аудитория: ${ctx.target_audience || 'широкая'}
Ключевые особенности: ${ctx.key_features || 'определи по фото'}
Стиль дизайна: ${ctx.style}
Цветовая схема: ${ctx.color_scheme}
Дополнительные инструкции: ${ctx.extra_instructions || 'нет'}

НА ОСНОВЕ ФОТО ТОВАРА определи:
1. Категорию товара
2. Основные визуальные характеристики (цвет, форма, материал, текстура)
3. УТП (уникальное торговое предложение)
4. Эмоциональные триггеры для покупателя

⚠️ КРИТИЧЕСКИ ВАЖНО — поле product_photo_description:
Опиши ДЕТАЛЬНО и ТОЧНО внешний вид товара с фото: форму, пропорции, все цвета, материалы, текстуры, надписи на товаре, логотипы, упаковку.

Создай данные для ПРОДАЮЩЕЙ карточки. Ответ строго JSON:
{
  "main_title": "Яркий заголовок (3-5 слов)",
  "subtitle": "Подзаголовок с ключевой выгодой",
  "bullet_points": ["5-7 коротких УТП с emoji"],
  "cta_text": "Призыв к действию",
  "seo_title": "SEO-заголовок",
  "seo_description": "SEO-описание 150-200 символов",
  "search_keywords": ["10-15 ключевых слов"],
  "category_suggestion": "Рекомендуемая категория",
  "color_palette": ["#hex1", "#hex2", "#hex3"],
  "visual_style_notes": "Рекомендации по визуальному оформлению",
  "product_photo_description": "ПОДРОБНОЕ описание внешнего вида товара на АНГЛИЙСКОМ",
  "rich_content_blocks": [
    { "type": "hero", "heading": "Заголовок", "text": "Описание" },
    { "type": "features", "heading": "Преимущества", "items": ["Пункт 1", "Пункт 2"] },
    { "type": "usage", "heading": "Как использовать", "steps": ["Шаг 1", "Шаг 2"] },
    { "type": "specs", "heading": "Характеристики", "items": {"Материал": "значение"} }
  ],
  "infographic_prompts": [
    "Промпт-вариант 1 (EN)",
    "Промпт-вариант 2 (EN)",
    "Промпт-вариант 3 (EN)"
  ],
  "a_plus_content": {
    "brand_story": "История бренда (2-3 предложения)",
    "comparison_table": {"columns": ["Наш товар", "Аналоги"], "rows": [["Преимущество 1", "Нет"]]}
  }
}

⚠️ ПРАВИЛА для infographic_prompts:
Модель flux-kontext-pro ПОЛУЧИТ ФОТО ТОВАРА АВТОМАТИЧЕСКИ как reference image.
Поэтому в промптах НЕ описывай сам товар — описывай ТОЛЬКО оформление:

1. Каждый промпт СТРОГО на АНГЛИЙСКОМ языке
2. НЕ описывай товар — модель увидит его на фото
3. Описывай: какой фон/сцену создать, какие маркетинговые элементы добавить
4. 3 РАЗНЫХ варианта для концепции "${ctx.concept}":
   - studio: белый/светлый фон, студийное освещение, иконки преимуществ
   - lifestyle: бытовая сцена (кухня, офис, парк), тёплые тона
   - flatlay: вид сверху, аксессуары вокруг, текстурный фон
   - minimal: однотонный фон, минимум декора, чистая типографика
   - model: на человеке/модели, модный фон
5. Каждый промпт содержит: описание сцены + маркетинговые элементы + формат вертикальный 9:16
6. ЗАПРЕЩЕНО: Midjourney-синтаксис (--ar, --v), описание самого товара`;

const messages = [
  { role: 'system', content: ctx.systemPrompt },
  {
    role: 'user',
    content: [
      { type: 'text', text: userPrompt },
      { type: 'image_url', image_url: { url: ctx.image_url, detail: 'high' } }
    ]
  }
];

const requestBody = JSON.stringify({
  model: ctx.model,
  messages: messages,
  max_tokens: 4000,
  temperature: 0.7
});

const url = ctx.baseUrl + '/chat/completions';

return [{ json: { url, body: requestBody, ...ctx } }];

const response = $input.first().json;
const prevCtx = $('🏗️ Запрос анализа фото').first().json;

let content = '';
try {
  content = response.choices[0].message.content;
} catch (e) {
  throw new Error('AI не вернул ответ: ' + JSON.stringify(response));
}

let cardData;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    cardData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('JSON не найден в ответе');
  }
} catch (e) {
  throw new Error('Ошибка парсинга JSON: ' + e.message + ' | Raw: ' + content.substring(0, 500));
}

return [{ json: {
  product_name: prevCtx.product_name,
  image_url: prevCtx.image_url,
  marketplace: prevCtx.marketplace,
  artikuls: prevCtx.artikuls,
  session_id: prevCtx.session_id,
  callback_url: prevCtx.callback_url,
  style: prevCtx.style,
  color_scheme: prevCtx.color_scheme,
  include_price: prevCtx.include_price,
  price: prevCtx.price,
  include_badge: prevCtx.include_badge,
  badge_text: prevCtx.badge_text,
  concept: prevCtx.concept,
  card_data: cardData,
  baseUrl: prevCtx.baseUrl,
  raw_ai_response: content
}}];

const ctx = $input.first().json;
const cardData = ctx.card_data;
const prompts = cardData.infographic_prompts || [];
const concept = ctx.concept || 'studio';

// Concept-specific default prompts (used if AI didn't provide them)
const conceptDefaults = {
  studio: [
    'Place this product on a clean white studio background with soft even lighting. Add professional feature callout badges around the product, quality certification icons, and elegant gradient accent. Vertical 9:16 marketplace infographic.',
    'Place this product on a light grey studio background with dramatic side lighting creating subtle shadows. Add numbered benefit icons on the left side and a promotional banner at the top. Vertical 9:16.',
    'Place this product centered on a warm cream studio background. Add circular feature badges around the product, satisfaction guarantee seal, and clean minimalist info panels. Vertical 9:16.'
  ],
  lifestyle: [
    'Place this product in a cozy home kitchen scene with warm natural lighting from a window. Add subtle feature callouts and lifestyle text overlays. Soft bokeh background. Vertical 9:16.',
    'Place this product in a modern office desk setting with plants and coffee cup nearby. Add professional infographic features: benefit icons, usage scenario labels. Natural daylight. Vertical 9:16.',
    'Place this product outdoors in a bright park setting. Active lifestyle context with happy vibes. Add benefit badges and a call-to-action banner. Vertical 9:16.'
  ],
  flatlay: [
    'Top-down flatlay: product centered on marble surface, surrounded by complementary accessories and decorative elements. Feature callout labels pointing to key benefits. Vertical 9:16.',
    'Top-down flatlay: product on wooden textured surface, styled with themed props around it. Clean infographic overlay with numbered benefits. Vertical 9:16.',
    'Top-down flatlay: product on pastel colored background with geometric shapes and artistic arrangement. Modern badge overlays with key specs. Vertical 9:16.'
  ],
  minimal: [
    'Product on solid white background with generous negative space. One bold headline, three minimal icons. Ultra-clean design. Vertical 9:16.',
    'Product floating on soft gradient background (light to slightly darker). Minimalist typography with product name and one key benefit. Vertical 9:16.',
    'Product on solid muted color background that complements it. Single feature highlight with elegant thin-line icons. Vertical 9:16.'
  ],
  model: [
    'Show this product being worn/used by a person in modern urban setting. Street style photography feel. Subtle info badges and brand banner. Vertical 9:16.',
    'Show this product in professional studio photoshoot. Model posing naturally. Product features and sizing info overlay. Vertical 9:16.',
    'Show this product in casual lifestyle context — person at home. Cozy warm tones. Trust badges and customer rating overlay. Vertical 9:16.'
  ]
};

const defaults = conceptDefaults[concept] || conceptDefaults.studio;

// Build 3 prompts: use AI-generated or fallback to concept defaults
const finalPrompts = [];
for (let i = 0; i < 3; i++) {
  let p = (prompts[i] || defaults[i] || defaults[0]);
  // Remove Midjourney flags
  p = p.replace(/\s*--[a-z]+\s+[\w:.]+/gi, '').trim();
  // Safety prefix
  p = 'Professional marketplace product infographic. Edit this product photo: ' + p + ' Eye-catching high-contrast design. Add decorative marketing elements, benefit icons, and promotional badges around the product.';
  finalPrompts.push(p);
}

return [{ json: { ...ctx, final_prompts: finalPrompts } }];

// Собираем task_ids от всех 3 вариантов
const ctx = $('🎨 3 промпта').first().json;
const v1 = $('🖼️ Вариант 1').first().json;
const v2 = $('🖼️ Вариант 2').first().json;
const v3 = $('🖼️ Вариант 3').first().json;

const taskIds = [
  { task_id: v1.id || null, code: v1.code, variant: 0, error: v1.code !== 0 ? JSON.stringify(v1).substring(0, 200) : null },
  { task_id: v2.id || null, code: v2.code, variant: 1, error: v2.code !== 0 ? JSON.stringify(v2).substring(0, 200) : null },
  { task_id: v3.id || null, code: v3.code, variant: 2, error: v3.code !== 0 ? JSON.stringify(v3).substring(0, 200) : null }
];

const validTasks = taskIds.filter(t => t.task_id);
if (validTasks.length === 0) {
  throw new Error('All variant creation requests failed: ' + JSON.stringify(taskIds));
}

return [{ json: {
  task_ids: taskIds,
  valid_count: validTasks.length,
  media_base_url: ctx.baseUrl,
  session_id: ctx.session_id,
  product_name: ctx.product_name,
  image_url: ctx.image_url,
  marketplace: ctx.marketplace,
  artikuls: ctx.artikuls,
  callback_url: ctx.callback_url,
  style: ctx.style,
  color_scheme: ctx.color_scheme,
  include_price: ctx.include_price,
  price: ctx.price,
  include_badge: ctx.include_badge,
  badge_text: ctx.badge_text,
  concept: ctx.concept,
  card_data: ctx.card_data,
  poll_count: 0
}}];

// Проверяем статус всех вариантов
const ctx = $input.first().json;
const taskIds = ctx.task_ids;
const baseUrl = ctx.media_base_url;

const results = [];
for (const t of taskIds) {
  if (!t.task_id) {
    results.push({ variant: t.variant, status: 'failed', url: null, error: t.error });
    continue;
  }
  // Check result via /media/result — using HttpRequest would need 3 nodes, so we call plain HTTP
  // Note: n8n credential header is already part of the calling context
  results.push({ variant: t.variant, task_id: t.task_id, status: 'pending' });
}

return [{ json: { ...ctx, variant_results: results } }];

// Собираем результаты проверки всех 3 вариантов
const ctx = $('📋 Подготовка').first().json;
const r1 = $('🔄 Статус 1').first().json;
const r2 = $('🔄 Статус 2').first().json;
const r3 = $('🔄 Статус 3').first().json;

const results = [
  { variant: 0, task_id: ctx.task_ids[0].task_id, status: r1.status || 'error', url: r1.url || null },
  { variant: 1, task_id: ctx.task_ids[1].task_id, status: r2.status || 'error', url: r2.url || null },
  { variant: 2, task_id: ctx.task_ids[2].task_id, status: r3.status || 'error', url: r3.url || null }
];

const terminal = ['done', 'failed', 'fail', 'error'];
const allDone = results.every(r => terminal.includes(r.status) || !r.task_id);
const doneCount = results.filter(r => r.status === 'done').length;

let pollCount = (ctx.poll_count || 0) + 1;

// Timeout after 30 polls (30 * 20s = 10 min)
if (!allDone && pollCount > 30) {
  results.forEach(r => {
    if (!terminal.includes(r.status)) {
      r.status = 'failed';
      r.error = 'Timeout after 10 minutes';
    }
  });
  return [{ json: { ...ctx, variant_results: results, all_done: true, done_count: doneCount, poll_count: pollCount } }];
}

return [{ json: { ...ctx, variant_results: results, all_done: allDone, done_count: doneCount, poll_count: pollCount } }];

// Собираем финальные результаты
const ctx = $input.first().json;
const results = ctx.variant_results;
const doneResults = results.filter(r => r.status === 'done' && r.url);
const tempUrls = results.map(r => r.url || null);

const aPlusContent = {
  ...(ctx.card_data.a_plus_content || {}),
  variant_task_ids: results.map(r => r.task_id || null),
  generation_model: 'flux-kontext-pro',
  variants_generated: doneResults.length,
  concept: ctx.concept
};

return [{ json: {
  product_name: ctx.product_name,
  image_url: ctx.image_url,
  marketplace: ctx.marketplace,
  artikuls: ctx.artikuls,
  session_id: ctx.session_id,
  callback_url: ctx.callback_url,
  style: ctx.style,
  color_scheme: ctx.color_scheme,
  include_price: ctx.include_price,
  price: ctx.price,
  include_badge: ctx.include_badge,
  badge_text: ctx.badge_text,
  concept: ctx.concept,
  card_data: ctx.card_data,
  a_plus_content_merged: aPlusContent,
  temp_urls: tempUrls,
  infographic_url: doneResults[0]?.url || null,
  infographic_variants: tempUrls.filter(u => u)
}}];

const saved = $('💾 Сохранить').first().json;
const minioResult = $('📥 В MinIO').first().json;
const collectResult = $('📎 Собрать результат').first().json;

const publicUrls = minioResult.publicUrls || collectResult.infographic_variants || [];

return [{ json: {
  success: true,
  card_id: saved.id,
  product_name: saved.product_name,
  concept: saved.concept,
  infographic_url: publicUrls[0] || collectResult.infographic_url,
  infographic_variants: publicUrls,
  variants_count: publicUrls.filter(u => u).length
}}];
